180	    private boolean doCompleted(String filename) {
181	         if (mListener == null)
182	            return true;
183	
184	        mCondition &= ~COREDUMP_COMPLETED;
185	        sendEvent(CODE_COREDUMP_COMPLETED, filename, mCoredumpPostWork);
186	        return waitCompleted();
187	    }
