#!/usr/bin/env node
const fs = require('fs');
const path = require('path');

const inputPath = process.argv[2];
const outputPath = process.argv[3];

if (!inputPath || !outputPath) {
  console.error('Usage: node ua-arch-analyze.js <input.json> <output.json>');
  process.exit(1);
}

let input;
try {
  input = JSON.parse(fs.readFileSync(inputPath, 'utf8'));
} catch (e) {
  console.error('Failed to read input file:', e.message);
  process.exit(1);
}

const { fileNodes, importEdges, allEdges } = input;

// ========== A. Directory Grouping ==========
function getCommonPrefix(paths) {
  if (!paths.length) return '';
  const segments = paths.map(p => p.split('/'));
  const minLen = Math.min(...segments.map(s => s.length));
  let prefix = [];
  for (let i = 0; i < minLen; i++) {
    const seg = segments[0][i];
    if (segments.every(s => s[i] === seg)) {
      prefix.push(seg);
    } else break;
  }
  return prefix.join('/');
}

function getTopLevelGroup(filePath) {
  const parts = filePath.split('/').filter(Boolean);
  return parts[0] || 'root';
}

const directoryGroups = {};
fileNodes.forEach(node => {
  const group = getTopLevelGroup(node.filePath);
  if (!directoryGroups[group]) directoryGroups[group] = [];
  directoryGroups[group].push(node.id);
});

// ========== B. Node Type Grouping ==========
const nodeTypeGroups = {};
fileNodes.forEach(node => {
  if (!nodeTypeGroups[node.type]) nodeTypeGroups[node.type] = [];
  nodeTypeGroups[node.type].push(node.id);
});

// ========== C. Import Adjacency Matrix ==========
const fanOut = {};
const fanIn = {};
const adjList = {};

fileNodes.forEach(n => { fanOut[n.id] = new Set(); fanIn[n.id] = new Set(); adjList[n.id] = []; });

importEdges.forEach(edge => {
  if (edge.type === 'imports') {
    fanOut[edge.source]?.add(edge.target);
    fanIn[edge.target]?.add(edge.source);
    adjList[edge.source]?.push(edge.target);
  }
});

// ========== D. Cross-Category Dependency Analysis ==========
const crossCategoryEdges = [];
const edgeTypeByCategory = {};

allEdges.forEach(edge => {
  const srcType = fileNodes.find(n => n.id === edge.source)?.type;
  const tgtType = fileNodes.find(n => n.id === edge.target)?.type;
  if (!srcType || !tgtType) return;

  const key = `${srcType} -> ${tgtType}`;
  if (!edgeTypeByCategory[key]) edgeTypeByCategory[key] = {};
  const ekey = edge.type || 'unknown';
  edgeTypeByCategory[key][ekey] = (edgeTypeByCategory[key][ekey] || 0) + 1;
});

Object.entries(edgeTypeByCategory).forEach(([cat, types]) => {
  const [srcType, tgtType] = cat.split(' -> ');
  Object.entries(types).forEach(([edgeType, count]) => {
    crossCategoryEdges.push({ fromType: srcType, toType: tgtType, edgeType, count });
  });
});

// ========== E. Inter-Group Import Frequency ==========
function getGroupForNode(nodeId) {
  const node = fileNodes.find(n => n.id === nodeId);
  if (!node) return null;
  return getTopLevelGroup(node.filePath);
}

const interGroupImports = {};
importEdges.forEach(edge => {
  if (edge.type !== 'imports') return;
  const fromGroup = getGroupForNode(edge.source);
  const toGroup = getGroupForNode(edge.target);
  if (!fromGroup || !toGroup) return;
  const key = `${fromGroup} -> ${toGroup}`;
  interGroupImports[key] = (interGroupImports[key] || 0) + 1;
});

const interGroupImportsList = Object.entries(interGroupImports).map(([key, count]) => {
  const [from, to] = key.split(' -> ');
  return { from, to, count };
});

// ========== F. Intra-Group Import Density ==========
const intraGroupDensity = {};
Object.entries(directoryGroups).forEach(([group, nodeIds]) => {
  let internalEdges = 0;
  let totalEdges = 0;

  nodeIds.forEach(nodeId => {
    (adjList[nodeId] || []).forEach(target => {
      const targetGroup = getGroupForNode(target);
      if (targetGroup === group) internalEdges++;
      totalEdges++;
    });
  });

  const nodeIdSet = new Set(nodeIds);
  nodeIds.forEach(nodeId => {
    (fanIn[nodeId] || new Set()).forEach(source => {
      if (nodeIdSet.has(source)) internalEdges++;
      totalEdges++;
    });
  });

  intraGroupDensity[group] = {
    internalEdges: internalEdges / 2,
    totalEdges,
    density: totalEdges > 0 ? (internalEdges / 2) / totalEdges : 0
  };
});

// ========== G. Directory Pattern Matching ==========
const patternMap = {
  'routes': 'api', 'api': 'api', 'controllers': 'api', 'endpoints': 'api', 'handlers': 'api',
  'services': 'service', 'core': 'service', 'lib': 'service', 'domain': 'service', 'logic': 'service',
  'models': 'data', 'db': 'data', 'data': 'data', 'persistence': 'data', 'repository': 'data', 'entities': 'data',
  'components': 'ui', 'views': 'ui', 'pages': 'ui', 'ui': 'ui', 'layouts': 'ui', 'screens': 'ui',
  'middleware': 'middleware', 'plugins': 'middleware', 'interceptors': 'middleware', 'guards': 'middleware',
  'utils': 'utility', 'helpers': 'utility', 'common': 'utility', 'shared': 'utility', 'tools': 'utility',
  'config': 'config', 'constants': 'config', 'env': 'config', 'settings': 'config',
  '__tests__': 'test', 'test': 'test', 'tests': 'test', 'spec': 'test', 'specs': 'test',
  'types': 'types', 'interfaces': 'types', 'schemas': 'types', 'contracts': 'types', 'dtos': 'types',
  'hooks': 'hooks', 'store': 'state', 'state': 'state', 'reducers': 'state', 'actions': 'state', 'slices': 'state',
  'assets': 'assets', 'static': 'assets', 'public': 'assets',
  'migrations': 'data', 'sql': 'data', 'database': 'data', 'schema': 'data',
  'docs': 'documentation', 'documentation': 'documentation', 'wiki': 'documentation',
  'deploy': 'infrastructure', 'deployment': 'infrastructure', 'infra': 'infrastructure', 'infrastructure': 'infrastructure',
  '.github': 'ci-cd', '.gitlab': 'ci-cd', '.circleci': 'ci-cd',
  'k8s': 'infrastructure', 'kubernetes': 'infrastructure', 'helm': 'infrastructure', 'charts': 'infrastructure',
  'terraform': 'infrastructure', 'tf': 'infrastructure',
  'docker': 'infrastructure',
  'script': 'config', 'management': 'config', 'commands': 'config',
  'opencore': 'service', 'eajni': 'middleware',
  'cpp': 'service',
  'java': 'service',
  'main': 'entry',
  'src': 'service'
};

const patternMatches = {};
Object.keys(directoryGroups).forEach(group => {
  patternMatches[group] = patternMap[group] || 'service';
});

// ========== H. Deployment Topology Detection ==========
const infraExtensions = ['.dockerfile', '.yml', '.yaml', '.tf', '.tfvars', '.sh'];
const deploymentTopology = {
  hasDockerfile: false,
  hasCompose: false,
  hasK8s: false,
  hasTerraform: false,
  hasCI: false,
  infraFiles: []
};

fileNodes.forEach(node => {
  const fp = node.filePath.toLowerCase();
  if (fp.includes('dockerfile')) { deploymentTopology.hasDockerfile = true; deploymentTopology.infraFiles.push(node.name); }
  if (fp.includes('docker-compose')) { deploymentTopology.hasCompose = true; deploymentTopology.infraFiles.push(node.name); }
  if (fp.includes('k8s') || fp.includes('kubernetes') || fp.includes('helm')) { deploymentTopology.hasK8s = true; deploymentTopology.infraFiles.push(node.name); }
  if (fp.endsWith('.tf') || fp.endsWith('.tfvars')) { deploymentTopology.hasTerraform = true; deploymentTopology.infraFiles.push(node.name); }
  if (fp.includes('.github/workflows') || fp.includes('.gitlab-ci') || fp.includes('jenkinsfile')) { deploymentTopology.hasCI = true; deploymentTopology.infraFiles.push(node.name); }
});

// ========== I. Data Pipeline Detection ==========
const dataPipeline = {
  schemaFiles: [],
  migrationFiles: [],
  dataModelFiles: [],
  apiHandlerFiles: []
};

fileNodes.forEach(node => {
  const ext = path.extname(node.filePath);
  if (ext === '.graphql' || ext === '.gql' || ext === '.proto' || ext === '.prisma') dataPipeline.schemaFiles.push(node.filePath);
  if (ext === '.sql' && node.filePath.includes('migrations')) dataPipeline.migrationFiles.push(node.filePath);
  if (node.filePath.includes('models') || node.filePath.includes('entity')) dataPipeline.dataModelFiles.push(node.filePath);
  if (node.filePath.includes('routes') || node.filePath.includes('handlers') || node.filePath.includes('endpoints')) dataPipeline.apiHandlerFiles.push(node.filePath);
});

// ========== J. Documentation Coverage ==========
const docExtensions = ['.md', '.rst', '.txt'];
const groupsWithDocs = new Set();
fileNodes.forEach(node => {
  if (docExtensions.includes(path.extname(node.filePath))) {
    const group = getTopLevelGroup(node.filePath);
    groupsWithDocs.add(group);
  }
});

const totalGroups = Object.keys(directoryGroups).length;
const docCoverage = {
  groupsWithDocs: groupsWithDocs.size,
  totalGroups,
  coverageRatio: totalGroups > 0 ? groupsWithDocs.size / totalGroups : 0,
  undocumentedGroups: Object.keys(directoryGroups).filter(g => !groupsWithDocs.has(g))
};

// ========== K. Dependency Direction ==========
const dependencyDirection = [];
const depMap = {};

interGroupImportsList.forEach(({ from, to, count }) => {
  const reverseKey = `${to} -> ${from}`;
  const reverseCount = interGroupImports[reverseKey] || 0;
  if (count > reverseCount) {
    dependencyDirection.push({ dependent: from, dependsOn: to });
    depMap[from] = to;
  } else if (reverseCount > count) {
    dependencyDirection.push({ dependent: to, dependsOn: from });
    depMap[to] = from;
  }
});

// ========== File Stats ==========
const filesPerGroup = {};
Object.entries(directoryGroups).forEach(([group, nodes]) => {
  filesPerGroup[group] = nodes.length;
});

const nodeTypeCounts = {};
fileNodes.forEach(n => {
  nodeTypeCounts[n.type] = (nodeTypeCounts[n.type] || 0) + 1;
});

const fileFanIn = {};
const fileFanOut = {};
fileNodes.forEach(n => {
  fileFanIn[n.id] = fanIn[n.id]?.size || 0;
  fileFanOut[n.id] = fanOut[n.id]?.size || 0;
});

// ========== OUTPUT ==========
const result = {
  scriptCompleted: true,
  directoryGroups,
  nodeTypeGroups,
  crossCategoryEdges,
  interGroupImports: interGroupImportsList,
  intraGroupDensity,
  patternMatches,
  deploymentTopology,
  dataPipeline,
  docCoverage,
  dependencyDirection,
  fileStats: {
    totalFileNodes: fileNodes.length,
    filesPerGroup,
    nodeTypeCounts
  },
  fileFanIn,
  fileFanOut
};

try {
  fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  process.exit(0);
} catch (e) {
  console.error('Failed to write output:', e.message);
  process.exit(1);
}
